// Resolvers with authorization checks to prevent IDOR vulnerabilities
const resolvers = {
  Query: {
    invoice: async (_, { id }, context) => {
      // Ensure the user is authenticated (context.user is set by auth middleware)
      if (!context.user || !context.user.id) {
        throw new Error('Authentication required.');
      }

      const invoice = invoicesDB[id];

      if (!invoice) {
        return null;
      }

      // SECURE: Authorization check — only allow access if the invoice belongs to the authenticated user.
      // This prevents Insecure Direct Object Reference (IDOR) where a user could
      // query any invoice by guessing or enumerating IDs.
      if (invoice.userId !== context.user.id) {
        throw new Error('Access denied. You do not have permission to view this invoice.');
      }

      return invoice;
    },

    myInvoices: async (_, __, context) => {
      // Ensure the user is authenticated
      if (!context.user || !context.user.id) {
        throw new Error('Authentication required.');
      }

      // SECURE: Only return invoices belonging to the authenticated user
      return Object.values(invoicesDB).filter(
        (invoice) => invoice.userId === context.user.id
      );
    }
  }
};

// Simulated authentication middleware (already verified user)
const authMiddleware = (req, res, next) => {
  // In production, this would extract and verify a JWT or session token.
  // For demonstration, we simulate an authenticated user from a verified token.
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Bearer ')) {
    // Simulated token-to-user mapping (in reality, JWT verification happens here)
    const token = authHeader.split(' ')[1];
    const tokenUserMap = {
      'valid-token-user-123': { id: 'user-123', email: 'alice@example.com', role: 'user' },
      'valid-token-user-456': { id: 'user-456', email: 'bob@example.com', role: 'user' },
    };
    req.user = tokenUserMap[token] || null;
  } else {
    req.user = null;
  }
  next();
};

async function startServer() {
  const app = express();

  app.use(authMiddleware);

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    context: ({ req }) => {
      // Pass the authenticated user into the GraphQL context
      return {
        user: req.user
      };
    },
    // Disable introspection in production to reduce attack surface
    introspection: process.env.NODE_ENV !== 'production',
  });

  await server.start();
  server.applyMiddleware({ app });

  const PORT = process.env.PORT || 4000;
  app.listen(PORT, () => {
    console.log(`Invoice API running at http://localhost:${PORT}${server.graphqlPath}`);
  });
}

startServer().catch(console.error);

